import { useState } from 'react'
import './FAQ.css'

const data = [
    {
        q: 'Чи захищені мої дані?',
        a: 'Так. Ми використовуємо банківські протоколи безпеки, сертифіковані GDPR та ISO.',
    },
    {
        q: 'Скільки коштує mWallet?',
        a: 'Нічого. mWallet безкоштовний для клієнтів mBank.',
    },
    {
        q: 'Якщо потрібна допомога?',
        a: 'Підтримка працює 24/7. Ми поруч у будь‑який час.',
    },
]

const FAQ = () => {
    const [openIndex, setOpenIndex] = useState(null)

    const toggle = (index) => {
        setOpenIndex(openIndex === index ? null : index)
    }

    return (
        <section className="faq" id="faq">
            <h2 className="faq-title">Питання та відповіді</h2>
            <div className="faq-list">
                {data.map((item, index) => (
                    <div
                        key={index}
                        className={`faq-item ${openIndex === index ? 'open' : ''}`}
                        onClick={() => toggle(index)}
                    >
                        <div className="faq-question">
                            {item.q}
                            <span className={`arrow ${openIndex === index ? 'rotate' : ''}`}>⌄</span>
                        </div>
                        {openIndex === index && (
                            <div className="faq-answer">
                                {item.a}
                            </div>
                        )}
                    </div>
                ))}
            </div>
        </section>
    )
}

export default FAQ
